import{_ as l,o as i,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const k=JSON.parse('{"title":"Flink基础架构","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/10-Flink学习/01-Flink基础架构.md","filePath":"语言/java/10-Flink学习/01-Flink基础架构.md","lastUpdated":1776149370000}'),n={name:"语言/java/10-Flink学习/01-Flink基础架构.md"};function t(h,a,o,_,s,d){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="flink基础架构" tabindex="-1">Flink基础架构 <a class="header-anchor" href="#flink基础架构" aria-label="Permalink to “Flink基础架构”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>Flink 基础架构描述了作业如何提交、调度、执行和容错。<br> 这是理解实时计算系统整体运转方式的起点。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>如果不理解基础架构，后面看状态、checkpoint、并行度和容错时会很零散。<br> 先建立整体视角，学习会顺畅很多。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>JobManager</li><li>TaskManager</li><li>Slot</li><li>并行度</li><li>作业图与执行图</li><li>资源调度基础认知</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解 Flink 是分布式执行系统</li><li>理解并行度和 slot 不是一个概念</li><li>理解作业运行依赖调度和资源分配</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>不理解作业为什么需要 slot</li><li>把并行度简单等同于机器数量</li><li>不了解任务拆分和执行模型</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>画一张 Flink 基础架构图</li><li>总结 JobManager 和 TaskManager 的职责</li><li>结合一个简单作业理解执行链路</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>JobManager 和 TaskManager 分别做什么</li><li>Slot 在 Flink 中承担什么角色</li><li>并行度为什么会直接影响吞吐</li></ul>',15)])])}const b=l(n,[["render",t]]);export{k as __pageData,b as default};
